#include <iostream>
using namespace std;
int main() {
    unsigned int N;
    cin >> N;
    unsigned num1 = 0;
    unsigned num2 = 0;
    unsigned int day2 = 0;
    unsigned int day1 = 1;
    if (N == 1) {
        unsigned int z;
        cin >> z;
        cout << "1";
    } else {
        for (int i = 1; i <= N; i++) {
            cin >> num2;
            if (i == 1) {
                num1 = num2;
                continue;
            }
            if (num2 > num1) {
                day1++;
            } else {
                if (day1 > day2) {
                    day2 = day1;
                    day1 = 1;
                } else {
                    day1 = 1;
                }
            }
            num1 = num2;

        }
        if (day1 > day2) {
            day2 = day1;
        }
        cout << day2;
    }
}
